// ============ SMART SELECTION (no-repeat, tier-aware, recency-weighted) ============
function selectQ(pool, seen, tier, n, tierLock) {
  if (!pool || !pool.length) return [];
  const base = tierLock ? pool.filter((x) => x.d >= tierLock) : pool;
  const src = base.length ? base : pool;
  const unseen = src.filter((x) => !seen.has(x.id));
  const chosen = []; const take = (arr) => { for (const it of arr) { if (chosen.length >= n) break; if (!chosen.includes(it)) chosen.push(it); } };
  const order = [tier, tier + 1, tier - 1, tier + 2, tier - 2].filter((t) => t >= 1 && t <= 5);
  for (const t of order) { take(shuffle(unseen.filter((x) => x.d === t))); if (chosen.length >= n) break; }
  if (chosen.length < n) take(shuffle(unseen));
  if (chosen.length < n) { const rec = src.filter((x) => !chosen.includes(x)); for (const t of order) { take(shuffle(rec.filter((x) => x.d === t))); if (chosen.length >= n) break; } if (chosen.length < n) take(shuffle(rec)); }
  return chosen.slice(0, n);
}

// ---- "choose the question" builder: answer shown, pick matching question ----
function buildChooseRound(pool, seen, tier, n, similar) {
  const picks = selectQ(pool, seen, tier, n);
  return picks.map((correct) => {
    // similar mode: prefer distractor questions from the same category for tighter difficulty
    const candidatePool = similar ? ALL_Q.filter((x) => x.cat === correct.cat) : ALL_Q;
    let cands = candidatePool.filter((x) => x.a !== correct.a && x.q !== correct.q);
    if (cands.length < 3) cands = ALL_Q.filter((x) => x.a !== correct.a && x.q !== correct.q);
    const distractors = shuffle(cands).slice(0, 3);
    const questionOptions = shuffle([correct, ...distractors]);
    return { answer: correct.a, correctQ: correct.q, options: questionOptions.map((x) => x.q), d: correct.d, id: correct.id, cat: correct.cat };
  });
}

// ---- "word builder": clue + scrambled letters (correct + distractors) ----
const AR_LETTERS = "ابتثجحخدذرزسشصضطظعغفقكلمنهوي".split("");
function buildBuilderRound(pool, seen, tier, n) {
  const candidates = pool.filter((x) => x.a.replace(/[^ء-ي]/g, "").length >= 3 && x.a.replace(/[^ء-ي]/g, "").length <= 8 && !x.a.includes(" "));
  const picks = selectQ(candidates.length >= n ? candidates : pool, seen, tier, n);
  return picks.map((it) => {
    const ans = it.a.replace(/[^ء-ي]/g, "");
    const letters = ans.split("");
    const distractCount = Math.min(5, Math.max(3, Math.ceil(letters.length * 0.6)));
    const distract = [];
    while (distract.length < distractCount) { const L = AR_LETTERS[(Math.random() * AR_LETTERS.length) | 0]; distract.push(L); }
    return { clue: it.q, answer: ans, pool: shuffle([...letters, ...distract]), d: it.d, id: it.id, cat: it.cat };
  });
}

// ============ PRIMITIVES ============
const Aurora = ({ q }) => {
  if (q === "off") return <div style={{ position: "fixed", inset: 0, zIndex: 0, background: C.bg0 }} />;
  return (
    <div style={{ position: "fixed", inset: 0, overflow: "hidden", zIndex: 0, pointerEvents: "none" }}>
      <div className="k-aur" style={{ background: `radial-gradient(circle,${C.violet},transparent 60%)`, top: "-12%", right: "-10%", animationPlayState: q === "medium" ? "paused" : "running" }} />
      <div className="k-aur" style={{ background: `radial-gradient(circle,${C.gold},transparent 62%)`, top: "20%", left: "-14%", animationDelay: "4s", opacity: .14, animationPlayState: q === "medium" ? "paused" : "running" }} />
      <div className="k-aur" style={{ background: `radial-gradient(circle,${C.cyan},transparent 60%)`, bottom: "-16%", left: "20%", animationDelay: "7s", animationPlayState: q === "medium" ? "paused" : "running" }} />
      {q === "high" && <div className="k-grain" />}
    </div>
  );
};
const Burst = ({ x, y, color, onDone }) => {
  const parts = useRef(Array.from({ length: 24 }, (_, i) => ({ a: (i / 24) * Math.PI * 2 + Math.random() * .3, d: 55 + Math.random() * 75, s: 3 + Math.random() * 6 }))).current;
  useEffect(() => { const t = setTimeout(onDone, 900); return () => clearTimeout(t); }, [onDone]);
  return <div style={{ position: "fixed", left: x, top: y, pointerEvents: "none", zIndex: 9999 }}>{parts.map((p, i) => <span key={i} style={{ position: "absolute", width: p.s, height: p.s, borderRadius: i % 3 ? "50%" : 1, background: color, boxShadow: `0 0 7px ${color}`, animation: "k-burst .9s cubic-bezier(.1,.7,.3,1) forwards", ["--tx"]: `${Math.cos(p.a) * p.d}px`, ["--ty"]: `${Math.sin(p.a) * p.d}px` }} />)}</div>;
};
const Panel = ({ children, style, glow, onClick, className = "" }) => (
  <div onClick={onClick} className={`k-panel ${className}`} style={{ position: "relative", background: `linear-gradient(160deg,${C.card},${C.card2})`, border: `1px solid ${C.line}`, borderRadius: 20, boxShadow: `0 16px 44px rgba(0,0,0,.42)${glow ? `,inset 0 0 26px ${glow}1c` : ""}`, ...style }}>
    {glow && <div style={{ position: "absolute", top: 0, left: 16, right: 16, height: 1, background: `linear-gradient(90deg,transparent,${glow},transparent)` }} />}
    {children}
  </div>
);
const Counter = ({ icon, val, c }) => (
  <div style={{ display: "flex", alignItems: "center", gap: 6, padding: "7px 12px", borderRadius: 13, background: "rgba(150,170,220,0.07)", border: `1px solid ${C.line}`, backdropFilter: "blur(10px)" }}>
    <Icon d={I[icon]} size={16} c={c} /><span style={{ fontWeight: 800, fontSize: 13.5, color: C.ink }}>{val}</span>
  </div>
);
const TierTag = ({ d, sm }) => <span style={{ fontSize: sm ? 10 : 11, fontWeight: 800, padding: sm ? "2px 8px" : "3px 10px", borderRadius: 8, background: `${TIERS[d - 1].c}1c`, color: TIERS[d - 1].c, border: `1px solid ${TIERS[d - 1].c}44` }}>{TIERS[d - 1].name}</span>;
const GoldBtn = ({ children, onClick, disabled, style, sm }) => (
  <button className="k-press k-gold" disabled={disabled} onClick={(e) => { if (!disabled) { SFX.tap(); onClick && onClick(e); } }}
    style={{ width: "100%", border: "none", borderRadius: 12, padding: sm ? "8px 12px" : "11px 16px", fontWeight: 800, fontSize: sm ? 13 : 14.5, fontFamily: "inherit", cursor: disabled ? "not-allowed" : "pointer", color: "#1c1407", background: `linear-gradient(135deg,${C.goldHi},${C.gold} 45%,${C.goldDeep})`, opacity: disabled ? .5 : 1, boxShadow: `0 6px 18px ${C.gold}33`, ...style }}>{children}</button>
);
const DarkBtn = ({ children, onClick, style, icon, disabled }) => (
  <button className="k-press" disabled={disabled} onClick={() => { if (!disabled) { SFX.tap(); onClick(); } }} style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, border: `1px solid ${C.line}`, borderRadius: 12, padding: "11px", fontWeight: 700, fontSize: 14, fontFamily: "inherit", cursor: "pointer", color: C.ink, background: "rgba(150,170,220,0.08)", opacity: disabled ? .5 : 1, ...style }}>{icon && <Icon d={I[icon]} size={17} />}{children}</button>
);
const IconBtn = ({ icon, onClick, c = C.ink }) => <button className="k-press" onClick={() => { SFX.nav(); onClick(); }} style={{ display: "grid", placeItems: "center", width: 42, height: 42, borderRadius: 12, background: "rgba(150,170,220,0.08)", border: `1px solid ${C.line}`, cursor: "pointer" }}><Icon d={I[icon]} size={20} c={c} /></button>;
const Bar = ({ pct, c = C.cyan, h = 9 }) => <div style={{ height: h, borderRadius: h, background: "rgba(150,170,220,0.12)", overflow: "hidden" }}><div style={{ height: "100%", width: `${Math.min(100, pct)}%`, background: `linear-gradient(90deg,${c},${c}bb)`, borderRadius: h, transition: "width .9s cubic-bezier(.2,.9,.2,1)", boxShadow: `0 0 10px ${c}55` }} /></div>;
const Deco = () => <svg width="60" height="12" viewBox="0 0 60 12"><path d="M0 6h44M48 2l4 4-4 4M44 6l4-4M44 6l4 4" stroke={C.gold} strokeWidth="1.5" fill="none" strokeLinecap="round" /></svg>;
const Header = ({ title, onBack, icon, color = C.gold, right }) => (
  <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 16 }}>
    <IconBtn icon="arrow" onClick={onBack} />
    <h2 style={{ margin: 0, fontSize: 21, fontWeight: 900, display: "flex", alignItems: "center", gap: 8, flex: 1 }}>{icon && <Icon d={I[icon]} size={22} c={color} />}{title}</h2>
    {right}
  </div>
);
const Empty = ({ icon, text }) => (
  <div style={{ textAlign: "center", padding: "50px 20px", color: C.inkDim }}>
    <Icon d={I[icon]} size={46} c={C.inkFaint} /><div style={{ marginTop: 12, fontSize: 14 }}>{text}</div>
  </div>
);
const Loader = ({ label = "جارٍ التحميل" }) => (
  <div className="k-fade" style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: "70vh", gap: 16 }}>
    <div className="k-spin" style={{ width: 46, height: 46, borderRadius: "50%", border: `3px solid ${C.line2}`, borderTopColor: C.gold }} />
    <div style={{ color: C.inkDim, fontSize: 14, fontWeight: 700 }}>{label}…</div>
  </div>
);

// ============ MAIN ============
export default function Kingdom() {
  const [screen, setScreen] = useState("hub");
  const [tab, setTab] = useState("home");
  const [mode, setMode] = useState(null);
  const [cat, setCat] = useState(null);
  const [round, setRound] = useState([]);
  const [qi, setQi] = useState(0);
  const [bursts, setBursts] = useState([]);
  const [result, setResult] = useState(null);
  const [levelFx, setLevelFx] = useState(false);
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState(null);
  const [themeTick, setThemeTick] = useState(0); // forces re-render on theme change

  const [settings, setSettings] = useState(DEFAULT_SETTINGS);
  const [p, setP] = useState({
    xp: 0, level: 23, coins: 12450, gems: 230, energy: 15, prestige: 0,
    streak: 12, seasonXp: 1200, seasonTier: 8, answeredTotal: 5842,
    seen: new Set(), history: [], unlockedAch: new Set(["a_first", "a_q100"]),
    inventory: new Set(),
    stats: { rounds: 184, answered: 5842, right: 5667, perfects: 12, best: 0.97, bossWins: 0, casesSolved: 0, towerBest: 0, rank: 3450, catPlayed: {}, mastery: {}, achGot: 2 },
    daily: { date: todaySeed(), missions: { roundsToday: 0, rightToday: 0, perfectsToday: 0 }, claimedM: new Set() },
  });
  const update = useCallback((fn) => setP((prev) => { const n = { ...prev }; fn(n); return n; }), []);

  // apply audio + theme whenever settings change
  useEffect(() => { SFX.setVol(settings.sfxVol, settings.musicVol); }, [settings.sfxVol, settings.musicVol]);
  useEffect(() => { applyTheme(settings.theme); setThemeTick((t) => t + 1); }, [settings.theme]);

  const showToast = useCallback((text, c = C.gold) => { setToast({ text, c, id: Date.now() }); setTimeout(() => setToast(null), 2200); }, []);

  const xpToNext = p.level * 120;
  const diff = diffById(settings.difficulty);
  const baseTier = Math.min(5, 1 + Math.floor((p.level - 1) / 5));
  const acc = p.stats.answered ? p.stats.right / p.stats.answered : .5;
  const playerTier = Math.max(1, Math.min(5, Math.round((baseTier + diff.tier) / 2)));

  useEffect(() => { if (p._lv) { SFX.levelup(); setLevelFx(true); const t = setTimeout(() => { setLevelFx(false); update(n => { n._lv = false; }); }, 1700); return () => clearTimeout(t); } }, [p._lv]);

  const go = useCallback((s) => { SFX.nav(); setScreen(s); }, []);

  // start a standard / special mode round (difficulty-aware)
  const begin = (m, c) => {
    SFX.nav();
    if (m.id === "challenge") { setMode(m); setScreen("challengeSetup"); return; }
    if (m.id === "detective") { setMode({ ...m, _cat: c, _diff: diff }); setCat(c || null); setScreen("detective"); return; }
    if (m.id === "tower") { setMode({ ...m, _diff: diff }); setScreen("tower"); return; }
    if (m.id === "roulette") { setMode({ ...m, _diff: diff }); setScreen("roulette"); return; }
    const pool = c ? catPool(c.id) : ALL_Q;
    const tier = diff.tier;
    let data;
    if (m.id === "choose") data = buildChooseRound(pool, p.seen, tier, m.n, diff.similar);
    else if (m.id === "builder") data = buildBuilderRound(pool, p.seen, tier, m.n);
    else data = selectQ(pool, p.seen, tier, m.n, diff.tier >= 4 ? Math.max(2, diff.tier - 1) : 0);
    if (!data || !data.length) { showToast("لا توجد أسئلة كافية لهذه الفئة", C.red); return; }
    setLoading(true);
    setMode({ ...m, _cat: c, _diff: diff, time: Math.round((m.time || 0) * diff.timeMul) });
    setCat(c || null); setRound(data); setQi(0);
    setTimeout(() => { setLoading(false); setScreen("play"); }, 280);
  };

  const grantRewards = (rightCount, totalCount, modeId, extra = {}) => {
    const tierMul = playerTier; const modeBonus = { rapid: 1.3, timed: 1.2, challenge: 1, choose: 1.25, builder: 1.4, detective: 1.5, tower: 1.5, roulette: 1.3 }[modeId] || 1;
    const rmul = (extra.scoreMul || 1) * diff.rewardMul;
    const gXp = Math.round(rightCount * (10 + tierMul * 3) * modeBonus * diff.xpMul * (extra.scoreMul || 1));
    const perfect = rightCount === totalCount && totalCount > 0;
    let gCoin = Math.round((rightCount * 9 * modeBonus + (perfect ? 40 : 0)) * rmul) + (extra.bonusCoin || 0);
    let gGem = (perfect ? 1 : 0) + (extra.bonusGem || 0);
    update((n) => {
      let nx = n.xp + gXp, lv = n.level, leveled = false;
      while (nx >= lv * 120) { nx -= lv * 120; lv++; leveled = true; }
      n.xp = nx; n.level = lv; n.coins += gCoin; n.gems += gGem; n.seasonXp += gXp;
      n.answeredTotal += totalCount;
      n.stats = { ...n.stats, rounds: n.stats.rounds + 1, answered: n.stats.answered + totalCount, right: n.stats.right + rightCount };
      if (perfect) n.stats.perfects++;
      if (extra.bossWin) n.stats.bossWins = (n.stats.bossWins || 0) + 1;
      if (extra.caseSolved) n.stats.casesSolved = (n.stats.casesSolved || 0) + 1;
      if (extra.towerFloor) n.stats.towerBest = Math.max(n.stats.towerBest || 0, extra.towerFloor);
      const c = mode?._cat?.id || cat?.id; if (c) n.stats.mastery = { ...n.stats.mastery, [c]: (n.stats.mastery[c] || 0) + rightCount };
      n.daily = { ...n.daily, missions: { roundsToday: n.daily.missions.roundsToday + 1, rightToday: n.daily.missions.rightToday + rightCount, perfectsToday: n.daily.missions.perfectsToday + (perfect ? 1 : 0) } };
      // recompute unlocked achievements
      const got = new Set(n.unlockedAch); ACHIEVEMENTS.forEach((a) => { if (achProgress(a, n).done) got.add(a.id); }); n.unlockedAch = got; n.stats.achGot = got.size;
      n._lv = leveled;
    });
    if (perfect || gGem) SFX.reward();
    return { xp: gXp, coin: gCoin, gem: gGem, perfect };
  };

  const finishRound = (rightCount, totalCount, extra = {}) => {
    const r = grantRewards(rightCount, totalCount, mode?.id, extra);
    setResult({ right: rightCount, total: totalCount, perfect: r.perfect, xp: r.xp, coin: r.coin, gem: r.gem, mode, ...extra });
    setScreen("result");
  };

  const addBurst = (ev, color) => { if (!ev || settings.animQuality === "off") return; const r = ev.currentTarget.getBoundingClientRect(); setBursts(b => [...b, { id: Date.now() + Math.random(), x: r.left + r.width / 2, y: r.top + r.height / 2, color }]); };
  const markSeen = (id, ok) => update(n => { n.seen = new Set(n.seen).add(id); n.history = [{ id, ok: !!ok, ts: Date.now() }, ...n.history].slice(0, 200); });

  const shared = { p, settings, setSettings, update, setScreen: go, setTab, begin, playerTier, acc, xpToNext, diff, showToast };
  const playProps = { mode, cat, round, qi, setQi, p, playerTier, finishRound, addBurst, markSeen, setScreen: go };
  const motionOff = settings.reduceMotion || settings.animQuality === "off";

  return (
    <div key={themeTick} dir={settings.language === "en" ? "ltr" : "rtl"} data-motion={motionOff ? "off" : "on"} className={settings.largeText ? "k-large" : ""}
      style={{ fontFamily: "'Tajawal','Cairo',sans-serif", minHeight: "100vh", background: `radial-gradient(ellipse at top,${C.bg1},${C.bg0})`, color: C.ink, position: "relative", overflow: "hidden", filter: settings.highContrast ? "contrast(1.12) saturate(1.1)" : "none" }}>
      <style>{CSS}</style>
      <Aurora q={motionOff ? "off" : settings.animQuality} />
      {levelFx && !motionOff && <div className="k-lvfx"><div style={{ textAlign: "center" }}><Icon d={I.crown} size={66} c={C.gold} /><div style={{ fontSize: 30, fontWeight: 900, color: C.gold, marginTop: 8 }}>المستوى {p.level}</div><div style={{ color: C.inkDim }}>{rankFor(p.level)}</div></div></div>}

      <div style={{ maxWidth: 470, margin: "0 auto", position: "relative", zIndex: 2, minHeight: "100vh", paddingBottom: screen === "hub" ? 78 : 0 }}>
        {loading ? <Loader /> : <>
          {screen === "hub" && <Hub {...shared} />}
          {screen === "play" && <Play {...playProps} />}
          {screen === "challengeSetup" && <ChallengeSetup {...{ mode, playerTier, diff, seen: p.seen, setScreen: go, markSeen }} />}
          {screen === "detective" && <DetectivePlay {...{ mode, p, diff, finishRound, markSeen, setScreen: go, addBurst }} />}
          {screen === "tower" && <TowerPlay {...{ mode, p, diff, grantRewards, markSeen, setScreen: go, addBurst, showToast }} />}
          {screen === "roulette" && <RoulettePlay {...{ mode, p, diff, begin, finishRound, markSeen, setScreen: go, addBurst }} />}
          {screen === "result" && result && <Result {...{ result, setScreen: go, begin }} />}
          {screen === "categories" && <CatScreen {...{ setScreen: go, begin }} />}
          {screen === "modes" && <ModeScreen {...{ setScreen: go, begin }} />}
          {screen === "profile" && <Profile {...{ p, setScreen: go, acc, playerTier, diff }} />}
          {screen === "settings" && <Settings {...{ settings, setSettings, update, p, setScreen: go, showToast }} />}
          {screen === "achievements" && <Achievements {...{ p, setScreen: go }} />}
          {screen === "leaderboard" && <Leaderboard {...{ p, setScreen: go }} />}
          {screen === "missions" && <Missions {...{ p, update, setScreen: go, begin, showToast }} />}
          {screen === "store" && <Store {...{ p, update, setScreen: go, showToast }} />}
          {screen === "seasons" && <Seasons {...{ p, update, setScreen: go, showToast }} />}
          {screen === "statistics" && <Statistics {...{ p, acc, setScreen: go }} />}
          {screen === "more" && <MoreMenu {...{ setScreen: go }} />}
        </>}
      </div>

      {screen === "hub" && <BottomNav tab={tab} setTab={setTab} setScreen={go} />}
      {bursts.map(b => <Burst key={b.id} {...b} onDone={() => setBursts(bs => bs.filter(x => x.id !== b.id))} />)}
      {toast && <div className="k-toast" style={{ borderColor: `${toast.c}66`, boxShadow: `0 10px 30px ${toast.c}33` }}><Icon d={I.spark} size={16} c={toast.c} />{toast.text}</div>}
    </div>
  );
}

// ============ HUB ============
function Hub({ p, setScreen, setTab, begin, playerTier, acc, xpToNext, diff }) {
  // every quick action routes to its OWN real destination — never a game mode
  const quick = [
    { name: "المهام اليومية", icon: "target", c: C.gold, badge: 3, go: () => { setTab("missions"); setScreen("missions"); } },
    { name: "التحديات", icon: "versus", c: C.rose, go: () => setScreen("achievements") },
    { name: "الموسم الحالي", icon: "shield", c: C.cyan, tag: "موسم التحف", go: () => setScreen("seasons") },
    { name: "المتجر", icon: "cart", c: C.gold, go: () => { setTab("store"); setScreen("store"); } },
  ];
  const foot = [
    { icon: "rank", label: "ترتيب العام", val: `#${p.stats.rank.toLocaleString("en")}`, go: () => setScreen("leaderboard") },
    { icon: "medal", label: "أفضل نتيجة", val: `${Math.round(p.stats.best * 100)}%`, go: () => setScreen("statistics") },
    { icon: "trophy", label: "الإنجازات", val: `${p.stats.achGot} / ${ACHIEVEMENTS.length}`, go: () => setScreen("achievements") },
    { icon: "fire", label: "سلسلة الانتصارات", val: `${p.streak} يوم`, go: () => setScreen("statistics") },
  ];
  return (
    <div className="k-fade">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "16px 16px 8px" }}>
        <div style={{ display: "flex", gap: 7 }}>
          <Counter icon="coin" val={p.coins.toLocaleString("en")} c={C.gold} />
          <Counter icon="gem" val={p.gems} c={C.cyan} />
          <Counter icon="flame" val={p.energy} c={C.amber} />
        </div>
        <div className="k-press" onClick={() => setScreen("profile")} style={{ display: "flex", alignItems: "center", gap: 9, cursor: "pointer" }}>
          <div style={{ textAlign: "left" }}><div style={{ fontSize: 11, color: C.inkDim, lineHeight: 1.2 }}>{rankFor(p.level)}</div><div style={{ fontSize: 13.5, fontWeight: 800, color: C.gold }}>المستوى {p.level}</div></div>
          <div style={{ display: "grid", placeItems: "center", width: 40, height: 40, borderRadius: 12, background: `linear-gradient(135deg,${C.goldHi},${C.goldDeep})`, boxShadow: `0 6px 16px ${C.gold}40` }}><Icon d={I.crown} size={21} c="#1c1407" /></div>
        </div>
      </div>

      <div style={{ textAlign: "center", padding: "14px 0 6px" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 14 }}>
          <Deco /><h1 style={{ margin: 0, fontSize: 33, fontWeight: 900, letterSpacing: ".01em", background: `linear-gradient(100deg,${C.goldDeep},${C.goldHi},${C.gold})`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", textShadow: `0 2px 20px ${C.gold}30` }}>مملكة المعرفة</h1><div style={{ transform: "scaleX(-1)" }}><Deco /></div>
        </div>
        <div style={{ color: C.inkDim, fontSize: 12.5, marginTop: 6 }}>تحدَّ عقلك... توسّع معرفتك... اصنع إنجازك</div>
      </div>

      <div style={{ padding: "8px 16px 0", display: "flex", flexDirection: "column", gap: 16 }}>
        <Panel style={{ padding: 16 }} glow={C.cyan}>
          <div style={{ display: "flex", alignItems: "center" }}>
            <div style={{ flex: 1, textAlign: "center" }}>
              <div style={{ fontSize: 11.5, color: C.inkDim, marginBottom: 4 }}>تقدمك للمستوى</div>
              <div style={{ fontSize: 22, fontWeight: 900, color: C.cyan }}>{Math.round((p.xp / xpToNext) * 100)}%</div>
              <div style={{ marginTop: 6, padding: "0 4px" }}><Bar pct={(p.xp / xpToNext) * 100} c={C.cyan} h={7} /></div>
            </div>
            <div style={{ width: 1, height: 52, background: C.line }} />
            <div style={{ flex: 1, textAlign: "center" }}><div style={{ fontSize: 11.5, color: C.inkDim, marginBottom: 4 }}>المستوى الحالي</div><div style={{ fontSize: 26, fontWeight: 900 }}>{p.level}</div></div>
            <div style={{ width: 1, height: 52, background: C.line }} />
            <div className="k-press" onClick={() => { SFX.nav(); setScreen("statistics"); }} style={{ flex: 1, textAlign: "center", cursor: "pointer" }}>
              <div style={{ fontSize: 11.5, color: C.inkDim, marginBottom: 4 }}>الأسئلة المجابة</div>
              <div style={{ fontSize: 16, fontWeight: 800 }}>{p.answeredTotal.toLocaleString("en")}</div>
            </div>
          </div>
        </Panel>

        {/* QUICK ACTIONS — each to its real screen */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr 1fr", gap: 10 }}>
          {quick.map((q, i) => (
            <button key={q.name} className="k-card k-press" onClick={() => { SFX.nav(); q.go(); }} style={{ animationDelay: `${i * 50}ms`, position: "relative", padding: "14px 6px", borderRadius: 16, background: `linear-gradient(160deg,${C.card},${C.card2})`, border: `1px solid ${C.line}`, cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", gap: 7 }}>
              {q.badge && <span style={{ position: "absolute", top: 7, left: 7, minWidth: 17, height: 17, padding: "0 4px", borderRadius: 9, background: C.red, color: "#fff", fontSize: 10.5, fontWeight: 800, display: "grid", placeItems: "center" }}>{q.badge}</span>}
              {q.tag && <span style={{ position: "absolute", top: -7, right: "50%", transform: "translateX(50%)", whiteSpace: "nowrap", padding: "2px 7px", borderRadius: 7, background: `linear-gradient(135deg,${C.goldHi},${C.goldDeep})`, color: "#1c1407", fontSize: 9, fontWeight: 800 }}>{q.tag}</span>}
              <Icon d={I[q.icon]} size={24} c={q.c} />
              <span style={{ fontSize: 11.5, fontWeight: 700, textAlign: "center", lineHeight: 1.2 }}>{q.name}</span>
            </button>
          ))}
        </div>

        {/* difficulty quick chip */}
        <button className="k-press" onClick={() => { SFX.nav(); setScreen("settings"); }} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "11px 14px", borderRadius: 14, background: `linear-gradient(120deg,${diff.c}1a,${C.card2})`, border: `1px solid ${diff.c}33`, cursor: "pointer", fontFamily: "inherit", color: C.ink }}>
          <span style={{ display: "flex", alignItems: "center", gap: 8, fontWeight: 700, fontSize: 13 }}><Icon d={I.target} size={17} c={diff.c} />مستوى الصعوبة الحالي</span>
          <span style={{ display: "flex", alignItems: "center", gap: 6, fontWeight: 800, color: diff.c }}>{diff.name}<Icon d={I.gear} size={15} c={C.inkDim} /></span>
        </button>

        {/* GAME MODES */}
        <div style={{ textAlign: "center", marginTop: 4 }}><h2 style={{ margin: 0, fontSize: 18, fontWeight: 900 }}>أوضاع اللعب</h2></div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
          {MODES.map((m, i) => (
            <div key={m.id} className="k-card" style={{ animationDelay: `${i * 45}ms`, position: "relative", overflow: "hidden", padding: 14, borderRadius: 18, background: `linear-gradient(165deg,${C.cardHi},${C.card2})`, border: `1px solid ${m.color}22`, display: "flex", flexDirection: "column" }}>
              <div style={{ position: "absolute", inset: 0, background: `radial-gradient(circle at 50% 0%,${m.color}1c,transparent 60%)` }} />
              {m.badge && <span style={{ position: "absolute", top: 10, left: 10, padding: "2px 8px", borderRadius: 8, background: m.badge === "جديد" ? C.green : C.red, color: "#fff", fontSize: 10, fontWeight: 800, zIndex: 2 }}>{m.badge}</span>}
              <div style={{ display: "grid", placeItems: "center", height: 56, position: "relative" }}>
                <div style={{ display: "grid", placeItems: "center", width: 54, height: 54, borderRadius: 16, background: `radial-gradient(circle,${m.color}26,${m.color}08)`, border: `1px solid ${m.color}33` }}><Icon d={I[m.icon]} size={28} c={m.color} /></div>
              </div>
              <div style={{ fontWeight: 800, fontSize: 15, textAlign: "center", marginTop: 8, position: "relative" }}>{m.name}</div>
              <div style={{ fontSize: 11, color: C.inkDim, textAlign: "center", marginTop: 4, lineHeight: 1.5, minHeight: 46, position: "relative" }}>{m.desc}</div>
              <GoldBtn sm onClick={() => begin(m, m.needsCat ? CATEGORIES[0] : null)} style={{ marginTop: 8, position: "relative" }}>{m.cta}</GoldBtn>
            </div>
          ))}
        </div>

        {/* CATEGORIES STRIP */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 4 }}>
          <h2 style={{ margin: 0, fontSize: 18, fontWeight: 900 }}>الفئات</h2>
          <button className="k-press" onClick={() => { SFX.nav(); setScreen("categories"); }} style={{ background: "none", border: "none", color: C.gold, fontWeight: 700, fontSize: 13, cursor: "pointer", fontFamily: "inherit", display: "flex", alignItems: "center", gap: 4 }}>عرض الكل <Icon d={I.arrow} size={15} c={C.gold} /></button>
        </div>
        <div className="k-scroll" style={{ display: "flex", gap: 10, overflowX: "auto", margin: "0 -16px", padding: "0 16px 6px" }}>
          {CATEGORIES.slice(0, 8).map((c) => (
            <button key={c.id} className="k-press" onClick={() => begin(MODES[0], c)} style={{ flexShrink: 0, width: 96, padding: "13px 8px", borderRadius: 16, background: `linear-gradient(160deg,${C.card},${C.card2})`, border: `1px solid ${c.color}22`, cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", gap: 7 }}>
              <div style={{ display: "grid", placeItems: "center", width: 42, height: 42, borderRadius: 13, background: `${c.color}18`, border: `1px solid ${c.color}33` }}><Icon d={I[c.icon]} size={22} c={c.color} /></div>
              <span style={{ fontSize: 12, fontWeight: 700 }}>{c.name}</span>
              <span style={{ fontSize: 9.5, color: C.inkDim }}>{catPool(c.id).length} سؤال</span>
            </button>
          ))}
        </div>

        {/* FOOTER STATS — clickable to real screens */}
        <Panel style={{ padding: 14, display: "flex", justifyContent: "space-between" }}>
          {foot.map((f, i) => (
            <React.Fragment key={f.label}>
              <div className="k-press" onClick={() => { SFX.nav(); f.go(); }} style={{ flex: 1, textAlign: "center", cursor: "pointer" }}>
                <Icon d={I[f.icon]} size={16} c={C.gold} />
                <div style={{ fontSize: 13, fontWeight: 900, marginTop: 3 }}>{f.val}</div>
                <div style={{ fontSize: 9.5, color: C.inkDim, marginTop: 1 }}>{f.label}</div>
              </div>
              {i < foot.length - 1 && <div style={{ width: 1, background: C.line }} />}
            </React.Fragment>
          ))}
        </Panel>
      </div>
    </div>
  );
}

